export const useCreateRecipeHook = () => {
	const createRecipe = useClientMutator<void>();

	return useCallback(
		(recipeInput: RecipeInput, signal?: AbortSignal) => {
			return createRecipe({
				url: `/commands/recipes`,
				method: "POST",
				headers: { "Content-Type": "application/json" },
				data: recipeInput,
				signal,
			});
		},
		[createRecipe],
	);
};

